    return str(x).strip()

def matches_rule(rule):
    txt = json.dumps(rule).lower()
    # merchant-specific
    if 'belles_cookbook_store' in txt:
        return True
    if merchant_id is not None and str(merchant_id).lower() in txt:
        return True

