        if isinstance(rule, dict):
            for k,v in rule.items():
                if 'mcc' in str(k).lower():
                    if isinstance(v, list):
                        vals += [str(i) for i in v]
                    else:
                        vals += re.findall(r'\d+', str(v))
        if vals and mcc not in vals:
