    if ('country' in txt or 'acquirer_country' in txt) and country is not None:
        vals = []
        if isinstance(rule, dict):
            for k,v in rule.items():
                lk = str(k).lower()
                if 'country' in lk:
                    if isinstance(v, list):
                        vals += [str(i) for i in v]
