        if str(scheme).lower() in pstr:
            for token in path:
                if re.fullmatch(r'[A-Za-z0-9]{1,3}', str(token)):
                    possible.add(str(token))
    # also include observed acis
    possible |= set(current_acis)
    for aci in possible:
        fee = find_fee(scheme, aci, total_amount)
        if fee is not None:
            results.append((scheme, aci, fee))

if not results:
